<template>
  <div class="container">
    <Navbar />
    <div class="row">
      <div class="col-md-8 offset-md-2">
        <h3 class="mb-4 text-center">我的提醒</h3>
        <RemindList :remindList="remindList" />
      </div>
    </div>
  </div>
</template>

<script>
import Navbar from '../components/Navbar.vue'
import RemindList from '../components/RemindList.vue'
export default {
  name: 'Remind',
  components: { Navbar, RemindList },
  data() {
    return {
      remindList: [], // 提醒列表
      userId: this.$cookies.get('userId') || 1 // 从Cookies获取用户ID
    }
  },
  mounted() {
    this.getRemindList()
  },
  methods: {
    // 获取提醒列表
    async getRemindList() {
      try {
        const res = await this.$axios.get('/remind/list', {
          params: { userId: this.userId }
        })
        if (res.data.code === 200) {
          this.remindList = res.data.data
        }
      } catch (err) {
        console.error(err)
        this.$message && this.$message.error('查询提醒失败！')
      }
    }
  }
}
</script>
